<?php
session_start();
$conn = new mysqli("localhost", "root", "", "agroconnect");
$conn->set_charset("utf8mb4");
if (!isset($_SESSION['rol']) || $_SESSION['rol'] != 'superadmin') { header("Location: login.php"); exit(); }
function tablaExiste($conn, $tabla) { $tabla=$conn->real_escape_string($tabla); $res=$conn->query("SHOW TABLES LIKE '$tabla'"); return $res && $res->num_rows>0; }
function contar($conn, $sql) { $res=$conn->query($sql); if(!$res) return 0; return intval(($res->fetch_assoc())['total'] ?? 0); }
$totalEmpresas=contar($conn,"SELECT COUNT(*) AS total FROM empresas");
$totalUsuarios=contar($conn,"SELECT COUNT(*) AS total FROM usuarios");
$totalJefes=contar($conn,"SELECT COUNT(*) AS total FROM usuarios WHERE rol='jefe'");
$totalTrabajadores=contar($conn,"SELECT COUNT(*) AS total FROM usuarios WHERE rol='trabajador'");
$tieneIncidencias=tablaExiste($conn,'incidencias'); $tieneSesiones=tablaExiste($conn,'sesiones_activas'); $tieneForo=tablaExiste($conn,'foro_temas');
$incidenciasAbiertas=$tieneIncidencias?contar($conn,"SELECT COUNT(*) AS total FROM incidencias WHERE estado IN ('abierta','en_revision')"):0;
$incidenciasCriticas=$tieneIncidencias?contar($conn,"SELECT COUNT(*) AS total FROM incidencias WHERE prioridad='alta' AND estado <> 'resuelta'"):0;
$usuariosOnline=$tieneSesiones?contar($conn,"SELECT COUNT(*) AS total FROM sesiones_activas WHERE ultima_actividad >= (NOW() - INTERVAL 10 MINUTE)"):0;
$labels=[]; $datosIncidencias=[];
for($i=6;$i>=0;$i--){ $fecha=date('Y-m-d', strtotime("-$i days")); $labels[]=date('d/m', strtotime($fecha)); if($tieneIncidencias){ $stmt=$conn->prepare("SELECT COUNT(*) AS total FROM incidencias WHERE DATE(fecha_creacion)=?"); $stmt->bind_param("s",$fecha); $stmt->execute(); $datosIncidencias[]=intval($stmt->get_result()->fetch_assoc()['total']); } else {$datosIncidencias[]=0;} }
$ultimasIncidencias=$tieneIncidencias?$conn->query("SELECT i.*, e.nombre AS empresa FROM incidencias i LEFT JOIN empresas e ON i.empresa_id=e.id ORDER BY i.fecha_creacion DESC LIMIT 5"):false;
$ultimosTemas=$tieneForo?$conn->query("SELECT ft.*, e.nombre AS empresa, u.nombre AS usuario FROM foro_temas ft LEFT JOIN empresas e ON ft.empresa_id=e.id LEFT JOIN usuarios u ON ft.usuario_id=u.id ORDER BY ft.fecha_creacion DESC LIMIT 5"):false;
$conectados=$tieneSesiones?$conn->query("SELECT s.*, u.nombre, u.rol, e.nombre AS empresa FROM sesiones_activas s LEFT JOIN usuarios u ON s.usuario_id=u.id LEFT JOIN empresas e ON u.empresa_id=e.id WHERE s.ultima_actividad >= (NOW() - INTERVAL 10 MINUTE) ORDER BY s.ultima_actividad DESC LIMIT 8"):false;
?>
