<div class="dashboard-grid two-columns"><div class="admin-card"><div class="section-title-row"><div><h3>Últimas incidencias</h3><p>Problemas reportados por las empresas.</p></div><a href="incidencias.php" class="small-link">Gestionar</a></div><?php if($ultimasIncidencias && $ultimasIncidencias->num_rows>0){ ?><div class="table-responsive"><table class="table align-middle"><thead><tr><th>Título</th><th>Empresa</th><th>Prioridad</th><th>Estado</th></tr></thead><tbody><?php while($i=$ultimasIncidencias->fetch_assoc()){ ?><tr><td><?php echo htmlspecialchars($i['titulo']); ?></td><td><?php echo htmlspecialchars($i['empresa'] ?? 'General'); ?></td><td><span class="badge bg-success"><?php echo htmlspecialchars($i['prioridad']); ?></span></td><td><?php echo htmlspecialchars($i['estado']); ?></td></tr><?php } ?></tbody></table></div><?php } else { ?><p class="text-muted mb-0">Todavía no hay incidencias registradas.</p><?php } ?></div>
